import React, { useState, useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';

// Importing components from your folder structure
import Hero from './components/sections/Hero';
import FlowerPetals from './components/animations/FlowerPetals';
import Countdown from './components/ui/Countdown';
import Timeline from './components/sections/Timeline';
import Gallery from './components/sections/Gallery';
import RSVPForm from './components/sections/RSVPForm';
import InvitationQR from './components/ui/InvitationQR';
import MusicPlayer from './components/ui/MusicPlayer';

function App() {
  const [submittedData, setSubmittedData] = useState(null);

  useEffect(() => {
    try {
      AOS.init({ duration: 1000, once: true });
    } catch (e) {
      console.error("AOS init error:", e);
    }
  }, []);

  return (
    <div className="bg-[#FAF9F6] min-h-screen">
      {/* 1. Music and Petals */}
      <MusicPlayer />
      <FlowerPetals />
      
      {/* 2. Hero Section */}
      <Hero />
      
      {/* 3. Timer */}
      <div className="py-10 bg-white shadow-sm">
        <Countdown targetDate="2026-12-04" />
      </div>

      {/* 4. Story */}
      <section className="py-20 max-w-5xl mx-auto px-6">
        <h2 className="text-center font-serif text-5xl mb-16 italic text-gray-800">Our Story</h2>
        <Timeline />
      </section>

      {/* 5. Photos */}
      <section className="py-10">
        <Gallery />
      </section>

      {/* 6. RSVP Area */}
      <section className="py-20 bg-[#1A1A1B] text-white">
        {!submittedData ? (
          <RSVPForm onSubmissionSuccess={(data) => setSubmittedData(data)} />
        ) : (
          <div className="flex flex-col items-center">
             <h2 className="font-serif text-3xl mb-8">Reservation Confirmed</h2>
             <InvitationQR guestName={submittedData.name} />
          </div>
        )}
      </section>

      <footer className="py-12 text-center text-gray-400 uppercase tracking-widest text-[10px]">
        Arjun & Diya — 2026
      </footer>
    </div>
  );
}

export default App;
